import React, { useEffect, useState } from 'react';
import {
    Container,
    Box,
    Typography,
    Paper,
    CircularProgress,
    Alert,
} from '@mui/material';
import { getModelMetrics } from '../services/api';
import AnalysisResults from '../components/AnalysisResults';
import { ModelMetrics } from '../types';

const Results: React.FC = () => {
    const [metrics, setMetrics] = useState<ModelMetrics | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const fetchMetrics = async () => {
            try {
                const data = await getModelMetrics();
                setMetrics(data.metrics);
            } catch (err) {
                setError('Failed to fetch metrics');
            } finally {
                setLoading(false);
            }
        };

        fetchMetrics();
    }, []);

    return (
        <Box sx={{ py: 6, minHeight: '100vh' }}>
            <Container maxWidth="lg">
                <Box sx={{ mb: 4, color: 'white', textAlign: 'center' }}>
                    <Typography
                        variant="h4"
                        sx={{
                            fontWeight: 'bold',
                            mb: 2,
                            textShadow: '0 2px 4px rgba(0,0,0,0.2)',
                        }}
                    >
                        Analysis Results
                    </Typography>
                    <Typography
                        variant="body1"
                        sx={{
                            opacity: 0.95,
                            textShadow: '0 1px 2px rgba(0,0,0,0.2)',
                        }}
                    >
                        View your intrusion detection analysis and model performance metrics
                    </Typography>
                </Box>

                <Paper
                    sx={{
                        background: 'rgba(255, 255, 255, 0.98)',
                        backdropFilter: 'blur(10px)',
                        border: '1px solid rgba(255, 255, 255, 0.3)',
                        p: 4,
                        borderRadius: 2,
                    }}
                >
                    {loading && (
                        <Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }}>
                            <CircularProgress sx={{ color: '#667eea' }} />
                        </Box>
                    )}

                    {error && (
                        <Alert severity="error" sx={{ mb: 3 }}>
                            {error}
                        </Alert>
                    )}

                    {!loading && !error && metrics && <AnalysisResults metrics={metrics} />}

                    {!loading && !error && !metrics && (
                        <Box sx={{ textAlign: 'center', py: 6 }}>
                            <Typography variant="body1" color="text.secondary">
                                No analysis results available yet. Please upload and analyze a dataset first.
                            </Typography>
                        </Box>
                    )}
                </Paper>
            </Container>
        </Box>
    );
};

export default Results;
